1711	\section{Separatedness}
1712	\label{sec:gr_separated}
1713	
1714	\begin{lemma}
1715	[\(\mathrm{Gr}(r,d)\) is separated over \(\mathbb{Z}\)]
1716	  \label{lem:gr_separated}
1717	  \lean{AlgebraicGeometry.Grassmannian.isSeparated}
1718	  \uses{def:gr_glued_scheme, def:gr_transition}
1719	  % SOURCE: [Nitsure], \S 1, sub-section "Separatedness" (read from
1720	  % references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L856-L860).
1721	  % SOURCE QUOTE:
1722	  % "The intersection of the diagonal of $\grass(r,d)$ with $U^I\times U^J$
1723	  %  can be seen to be the closed subscheme $\Delta_{I,J}\subset U^I\times U^J$
1724	  %  defined by entries of the matrix formula $X^J_I\,X^I - X^J =0$,
1725	  %  and so $\grass(r,d)$ is a separated scheme."
1726	  \textit{Source: [Nitsure], \S 1.}
1727	  The structure morphism \(\mathrm{Gr}(r,d) \to \Spec \mathbb{Z}\)
1728	  (\cref{def:gr_glued_scheme}) is separated; equivalently, the diagonal
1729	  \(\Delta : \mathrm{Gr}(r,d) \to \mathrm{Gr}(r,d) \times_{\mathbb{Z}}
1730	  \mathrm{Gr}(r,d)\) is a closed immersion.
1731	\end{lemma}
1732	
1733	% SOURCE QUOTE PROOF: "The intersection of the diagonal of $\grass(r,d)$ with
1734	% $U^I\times U^J$ can be seen to be the closed subscheme
1735	% $\Delta_{I,J}\subset U^I\times U^J$ defined by entries of the matrix formula
1736	% $X^J_I\,X^I - X^J =0$, and so $\grass(r,d)$ is a separated scheme."
1737	% (references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L856-L860.)
1738	\begin{proof}
1739	  \uses{def:gr_glued_scheme, def:gr_transition}
1740	  The products \(U^I \times_{\mathbb{Z}} U^J\), as \(I, J\) range over the
1741	  size-\(d\) subsets, form an affine open cover of \(\mathrm{Gr}(r,d)
1742	  \times_{\mathbb{Z}} \mathrm{Gr}(r,d)\). Separatedness may be checked on this
1743	  cover: it suffices to show that for each pair \((I,J)\) the preimage
1744	  \(\Delta^{-1}(U^I \times_{\mathbb{Z}} U^J)\) maps by a closed immersion into
1745	  \(U^I \times_{\mathbb{Z}} U^J\), i.e.\ that the corresponding ring
1746	  homomorphism is surjective.
1747	
1748	  By \cref{def:gr_glued_scheme} the diagonal preimage is the overlap
1749	  \(\Delta^{-1}(U^I \times_{\mathbb{Z}} U^J) = U^I \cap U^J = U^I_J = \Spec
1750	  \mathbb{Z}[X^I, 1/P^I_J]\). The restricted diagonal corresponds to the ring map
1751	  \[
1752	    \delta_{I,J} : \mathbb{Z}[X^I] \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]
1753	    \longrightarrow \mathbb{Z}[X^I, 1/P^I_J],
1754	    \qquad
1755	    X^I \otimes 1 \mapsto X^I, \quad 1 \otimes X^J \mapsto (X^I_J)^{-1} X^I,
1756	  \]
1757	  the second component being the comorphism \(\theta_{I,J}\) of
1758	  \cref{def:gr_transition} (a point of \(U^I_J\) and its image under
1759	  \(\theta_{I,J}\) are the two coordinates of a point of the diagonal). We claim
1760	  \(\delta_{I,J}\) is surjective. Its image contains all entries of \(X^I\)
1761	  (from the first factor). From the second factor it contains the entries of
1762	  \((X^I_J)^{-1} X^I\); taking the \(I\)-minor of this matrix, and using
1763	  \(X^I_I = 1_{d\times d}\), the image contains the entries of \((X^I_J)^{-1}\),
1764	  and in particular
1765	  \[
1766	    \delta_{I,J}(1 \otimes P^J_I) = \det\bigl((X^I_J)^{-1}\bigr) = 1/P^I_J .
1767	  \]
1768	  Hence \(1/P^I_J\) lies in the image, so the image is all of
1769	  \(\mathbb{Z}[X^I, 1/P^I_J]\) and \(\delta_{I,J}\) is surjective. Concretely the
1770	  closed subscheme \(\Delta_{I,J} \subseteq U^I \times_{\mathbb{Z}} U^J\) is cut
1771	  out by the entries of the matrix relation
1772	  \[
1773	    X^J_I \, X^I - X^J \;=\; 0,
1774	  \]
1775	  which on the diagonal holds because \(X^J = (X^I_J)^{-1} X^I\) forces
1776	  \(X^J_I = (X^I_J)^{-1} X^I_I = (X^I_J)^{-1}\) and therefore \(X^J_I X^I =
1777	  (X^I_J)^{-1} X^I = X^J\). As each restricted diagonal is a closed immersion,
1778	  \(\Delta\) is a closed immersion and \(\mathrm{Gr}(r,d)\) is separated over
1779	  \(\mathbb{Z}\).
1780	\end{proof}
